def solve(s: str, k: int) -> str:
    result = []
    for char in s:
        if char.isalpha():
            result.append(char)
        elif char == '*':
            if result:
                result.pop()
        elif char == '#':
            result.extend(result.copy())
        elif char == '%':
            result = result[::-1]
    if k < len(result):
        return result[k]
    else:
        return '.'
